import{_ as i,o as l,c as e,a2 as r}from"./chunks/framework.BEgbRHOA.js";const p=JSON.parse('{"title":"Магазины","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier-admin/stores.md","filePath":"guide/xcourier-admin/stores.md","lastUpdated":1775746985000}'),t={name:"guide/xcourier-admin/stores.md"};function o(d,a,s,n,h,c){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="магазины" tabindex="-1">Магазины <a class="header-anchor" href="#магазины" aria-label="Permalink to &quot;Магазины&quot;">​</a></h1><h2 id="список-магазинов" tabindex="-1">Список магазинов <a class="header-anchor" href="#список-магазинов" aria-label="Permalink to &quot;Список магазинов&quot;">​</a></h2><p>Администратор видит все магазины платформы с информацией:</p><ul><li>Название и логотип</li><li>Адрес</li><li>Статус (открыт, закрыт, временно закрыт, скрыт)</li><li>Количество заказов за неделю</li></ul><h2 id="создание-магазина" tabindex="-1">Создание магазина <a class="header-anchor" href="#создание-магазина" aria-label="Permalink to &quot;Создание магазина&quot;">​</a></h2><p>Для создания нового магазина заполняются:</p><ul><li>Название</li><li>Телефон</li><li>Адрес (с автоподсказками и геокодированием)</li><li>Координаты (широта, долгота) — определяются автоматически по адресу</li><li>Логотип</li><li>Время доставки (мин/макс в минутах)</li><li>Расписание работы по дням недели</li></ul><h2 id="редактирование-магазина" tabindex="-1">Редактирование магазина <a class="header-anchor" href="#редактирование-магазина" aria-label="Permalink to &quot;Редактирование магазина&quot;">​</a></h2><p>Все поля магазина можно изменить. Дополнительно доступно:</p><ul><li>Переключатель <code>active</code> — скрыть/показать магазин в клиентском приложении</li><li>Переключатель <code>temporarilyClosed</code> — временно закрыть магазин</li></ul><h2 id="расписание-работы" tabindex="-1">Расписание работы <a class="header-anchor" href="#расписание-работы" aria-label="Permalink to &quot;Расписание работы&quot;">​</a></h2><p>Для каждого дня недели задаётся:</p><ul><li>Время открытия</li><li>Время закрытия</li><li>Признак выходного дня</li></ul><p>Расписание влияет на статус магазина — вне рабочих часов магазин автоматически показывается как «Закрыт».</p><h2 id="категории-магазина" tabindex="-1">Категории магазина <a class="header-anchor" href="#категории-магазина" aria-label="Permalink to &quot;Категории магазина&quot;">​</a></h2><p>Из карточки магазина можно перейти к управлению его категориями:</p><ul><li>Создание категорий</li><li>Изменение порядка сортировки</li><li>Включение/отключение категорий</li><li>Просмотр количества товаров в категории</li></ul><h2 id="поиск-адреса" tabindex="-1">Поиск адреса <a class="header-anchor" href="#поиск-адреса" aria-label="Permalink to &quot;Поиск адреса&quot;">​</a></h2><p>При создании или редактировании магазина доступен экран поиска адреса с автоподсказками. Координаты определяются автоматически из выбранного адреса.</p>',19)])])}const _=i(t,[["render",o]]);export{p as __pageData,_ as default};
